event.description:
InputEvent descriptor:
  Key: {type:"key", key:"Space", pressed:true, shift?:bool, ctrl?:bool, alt?:bool} or {type:"key", keycode:32, pressed:true}
  Mouse button: {type:"mouse_button", button_index:1, pressed:true, position:{x,y}, double_click?:bool} (1=left, 2=right, 3=middle)
  Mouse motion: {type:"mouse_motion", position:{x,y}, relative?:{x,y}}
  Action (named input from the InputMap): {type:"action", action:"jump", pressed:true, strength?:1.0}
